import React from "react";
import { Form } from "react-bootstrap";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

function SchemeMastersForm({ module }) {
   return (
      <div className="card border-0 shadow-sm">
         <div className="card-header border-0" style={{ background: module.bg, borderLeft: `5px solid ${module.color}` }} >
            <div className="d-flex align-items-center">
               <div>
                  <h5 className="card-title m-0 fw-bold" style={{ color: module.color }} >
                     {module.formTitle}
                  </h5>
                  <small>
                     Fill in the details below and save.
                  </small>
               </div>
            </div>
         </div>

         <div className="card-body" style={{ minHeight: "600px" }}>
            {/* Dynamic form here */}
         </div>
      </div>
   );
}

export default SchemeMastersForm;
